import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.DIMps2S2.js";const u=JSON.parse('{"title":"股东大会","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/corporate-actions/general-meeting.md","filePath":"zh-CN/stock-trading/corporate-actions/general-meeting.md"}'),o={name:"stock-trading/corporate-actions/general-meeting.md"};function n(l,a,s,h,c,d){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="股东大会" tabindex="-1">股东大会 <a class="header-anchor" href="#股东大会" aria-label="Permalink to &quot;股东大会&quot;">​</a></h1><p>股东大会类型、参与资格、投票机制及长桥的处理方式。</p><h2 id="股东大会类型" tabindex="-1">股东大会类型 <a class="header-anchor" href="#股东大会类型" aria-label="Permalink to &quot;股东大会类型&quot;">​</a></h2><p>上市公司召开的股东大会分为两类：</p><p><strong>股东周年大会（AGM，Annual General Meeting）</strong>：每年定期召开，通常用于审议年度报告、批准股息分派、选举董事及委任核数师等常规事项。港股上市公司须在每个财政年度结束后一定期限内召开。</p><p><strong>特别股东大会（EGM，Extraordinary General Meeting）</strong>：在股东周年大会以外召开，用于处理需要股东批准的特定事项，如重大资产收购、合并、供股计划、更改公司章程等。</p><h2 id="参与资格" tabindex="-1">参与资格 <a class="header-anchor" href="#参与资格" aria-label="Permalink to &quot;参与资格&quot;">​</a></h2><p>持有股票并不等同于自动获得投票资格。判断是否有资格参与投票的关键日期是<strong>登记日（Record Date）</strong>。</p><p>在登记日收市后持仓的股东，才有权就该次大会的议案行使投票权。登记日通常在股东大会召开日前数个交易日。</p><h2 id="委托代理投票" tabindex="-1">委托代理投票 <a class="header-anchor" href="#委托代理投票" aria-label="Permalink to &quot;委托代理投票&quot;">​</a></h2><p>长桥客户的股票以**代名人（Nominee）**方式持有，即股票登记在长桥托管机构名下，而非客户本人名下。</p><p>在代名人持股架构下：</p><ul><li>客户不会直接收到大会通知或委托书</li><li>客户无法以个人名义直接出席股东大会或行使投票权</li><li>长桥目前不提供代理投票转达服务</li></ul><p>如需就特定议案行使投票权，需在登记日前将股票转出至独立托管账户，以本人名义登记持股。</p><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><p>长桥 App → 资产 → 全部功能 → 公司行动 → 股东大会</p><h2 id="如何查看股东大会资讯" tabindex="-1">如何查看股东大会资讯 <a class="header-anchor" href="#如何查看股东大会资讯" aria-label="Permalink to &quot;如何查看股东大会资讯&quot;">​</a></h2><p>股东大会相关公告可通过以下渠道查阅：</p><ul><li><strong>长桥 App</strong>：资产 → 全部功能 → 公司行动 → 股东大会，查看与持仓相关的大会通知</li><li><strong>长桥 App 个股页面</strong>：全景 → 公告，查看上市公司发布的会议通告</li><li><strong>港交所披露易</strong>（hkexnews.hk）：查询港股公告全文</li><li><strong>新加坡交易所 SGXNet</strong>：查询新加坡上市公司公告</li></ul><h2 id="对持仓的影响" tabindex="-1">对持仓的影响 <a class="header-anchor" href="#对持仓的影响" aria-label="Permalink to &quot;对持仓的影响&quot;">​</a></h2><p>股东大会本身不直接影响持仓数量或股价，但大会通过的决议可能触发其他公司行动（如派息、供股、拆合股），届时按对应公司行动规则处理。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/corporate-actions/dividend">派息</a> — 股息分派的参与条件与处理</li><li><a href="/wiki/stock-trading/corporate-actions/rights-issue">供股要约</a> — 股东大会批准后触发的供股流程</li><li><a href="/wiki/market-data/announcements">公告与讨论</a> — 在 App 内查看公司公告</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/corporate-actions">公司行动</a></li><li><a href="/wiki/stock-trading">股票交易</a></li></ul>',25)])])}const g=e(o,[["render",n]]);export{u as __pageData,g as default};
